import React, { useEffect, useState } from 'react';
import { StyleSheet, Text, View, FlatList, TextInput, Button, ActivityIndicator } from 'react-native';
import axios from 'axios';

// Android emulator uses 10.0.2.2 to reach host localhost
const API_URL = 'http://10.0.2.2:8000';

export default function App() {
  const [todos, setTodos] = useState([]);
  const [title, setTitle] = useState('');
  const [loading, setLoading] = useState(false);

  const fetchTodos = async () => {
    setLoading(true);
    try {
      const res = await axios.get(`${API_URL}/todos`);
      setTodos(res.data);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const addTodo = async () => {
    if (!title.trim()) return;
    try {
      await axios.post(`${API_URL}/todos`, { title });
      setTitle('');
      fetchTodos();
    } catch (e) {
      console.error(e);
    }
  };

  useEffect(() => {
    fetchTodos();
  }, []);

  return (
    <View style={styles.container}>
      <Text style={styles.header}>Todo List</Text>
      {loading ? (
        <ActivityIndicator />
      ) : (
        <FlatList
          data={todos}
          keyExtractor={item => item.id.toString()}
          renderItem={({ item }) => (
            <Text style={styles.todo}>{item.title}</Text>
          )}
        />
      )}
      <View style={styles.inputContainer}>
        <TextInput
          style={styles.input}
          placeholder="New todo"
          value={title}
          onChangeText={setTitle}
        />
        <Button title="Add" onPress={addTodo} />
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, paddingTop: 50, paddingHorizontal: 20 },
  header: { fontSize: 24, fontWeight: 'bold', marginBottom: 20 },
  todo: { fontSize: 18, paddingVertical: 5 },
  inputContainer: { flexDirection: 'row', marginTop: 20, alignItems: 'center' },
